BEGIN;

INSERT INTO blog_posts (author_id, title, slug, content, excerpt, language, tags, is_published, published_at)
VALUES
(
    (SELECT id FROM users WHERE username = 'astrosander' LIMIT 1),
    'Июньский конкурс. Эксклюзивный мерч лучшим авторам месяца',
    'iyun-2026-konkurs-mercha',
    E'# Июньский конкурс. Эксклюзивный мерч лучшим авторам месяца\n\n### С 1 по 30 июня 2026 года на savchenkosolutions.com проходит первый ежемесячный конкурс авторов решений. Публикуй новые решения в LaTeX и выигрывай фирменный мерч платформы.\n\n---\n\n## Что мы устраиваем\n\nКонкурс стартует сегодня, в понедельник 1 июня, и идёт до конца месяца. Каждый, кто публикует новое решение к задаче Савченко за этот месяц, автоматически участвует. Никакой регистрации в конкурсе, никаких дополнительных кнопок. Просто решай задачи и публикуй разборы в LaTeX. Всё остальное за тебя сделает живая таблица результатов.\n\nЛучшим авторам месяца уезжают наборы мерча с фирменной символикой платформы. Кепка, худи и шопер.\n\nИдею предложил `emixter` в общем чате две недели назад. Я доработал формат так, чтобы шанс на приз был у каждого активного автора, а не только у двух очевидных фаворитов.\n\n![Фирменный мерч платформы. Худи, кепка и шопер](/img/blog/emixter_merch-front.jpeg)\n\n*Фирменный мерч платформы Savchenko Solutions. Худи, кепка и шопер.*\n\n![Тот же набор сбоку](/img/blog/contest_merch_side.jpeg)\n\n*Тот же набор сбоку. Кепка, худи и шопер.*\n\n## Призы\n\nПризы реальные, физические, доставляются международно за наш счёт.\n\n**Гран-при, один человек.** Полный набор. Кепка, худи, шопер. Получает автор, набравший больше всех баллов за месяц.\n\n**Серебро, один человек.** Полный набор. Кепка, худи, шопер. Получает второе место по баллам.\n\n**Бронза, несколько человек.** Фирменная кепка. Получает каждый, кто набрал не меньше 15 баллов за месяц.\n\nЭтот тираж мерча выпущен ограниченной партией на производстве Creative Depo. Тираж эксклюзивный, повторного выпуска не планируется. То, что уедет победителям июня, больше нигде не появится.\n\n![Партия мерча в упаковке производителя](/img/blog/emixter_merch-box.jpeg)\n\n*Партия фирменного мерча в упаковке производителя.*\n\n## Правила\n\nЗасчитывается каждое новое решение к задаче из сборника Савченко, опубликованное с 1 по 30 июня 2026 года включительно. К каждому решению есть три требования.\n\nРешение должно быть набрано в LaTeX, а не загружено как фото. Фотографии красивые, но их нельзя проиндексировать поисковиками, скопировать, перевести или процитировать. LaTeX остаётся навсегда.\n\nРешение должно быть оригинальным. Не перевод уже существующего решения, а собственный разбор задачи. Перевод полезен, но в этом конкурсе мы поощряем именно новый материал.\n\nРешение должно содержать рассуждение, а не только финальный ответ. Хотя бы одна формула с пояснением. Хотя бы один абзац о том, какая физика стоит за выбором подхода.\n\nЕсли все три требования выполнены, решение получает 1 балл. Дальше работают множители.\n\n## Множители\n\nПлатформа поощряет работу там, где её больше всего не хватает. Поэтому за разные категории решений начисляется разный множитель.\n\n| Категория | Множитель |\n|---|---:|\n| Базовое решение по правилам выше | 1.0 |\n| Решение к ранее нерешённой задаче | 1.5 |\n| Решение в главах 9, 10, 12 или 14 (покрытие меньше 50%) | 1.5 |\n| Решение на английском языке | 1.5 |\n\nМножители стакаются. Решение к ранее нерешённой задаче из главы 12, написанное по-английски, даёт 1.5 × 1.5 × 1.5 = 3.375 балла за одну запись.\n\nЭто значит, что силой 30 точно выбранных решений можно обогнать соперника, штурмующего платформу с 50 базовыми. Стратегия имеет значение.\n\n## Живая таблица\n\nСтраница конкурса находится по адресу [savchenkosolutions.com/challenge/iyun-2026](/challenge/iyun-2026). Она обновляется в реальном времени.\n\nНа странице видно текущую позицию каждого участника, общий счётчик новых решений за месяц, ленту последних опубликованных разборов и прогресс сообщества к общей цели. Наша общая цель на июнь это 250 новых решений. Если справимся, в июле объявим следующий конкурс с ещё более амбициозной целью.\n\nБаннер со ссылкой на конкурс висит на каждой странице сайта в течение всего месяца.\n\n## Кто, по нашим прогнозам, в гонке\n\nЭто конкурс, а не лотерея. Победителей определяют баллы. Но цифры за последние месяцы дают предсказуемых фаворитов.\n\n`igor` пишет много и концентрированно, с явной специализацией на электромагнетизме. `jzmicer` силён в термодинамике и магнетизме и вполне может побороться за серебро. В зону бронзы при сосредоточенной работе способны зайти многие авторы из середины рейтинга.\n\nЕсли твоего имени здесь нет, это не значит, что у тебя нет шансов. Это значит, что у тебя есть прекрасная возможность стать сюрпризом конкурса.\n\n`emixter` и я в конкурсе не участвуем. Наши наборы уже закреплены за нами как за авторами и кураторами платформы. Так у активных авторов сообщества остаётся чистый шанс на победу без соперничества с основателями.\n\n## Откуда взялась идея\n\n`emixter` написал в общий чат 13 мая. Привожу его сообщение в укороченном виде.\n\n> Я бы хотел, чтобы люди решали. Думаю ты тоже этого хочешь. Один мерч мне, один тебе. А два разыграть на сайте, кто первым опубликует 50 задач в латехе, а не фото. Только новые задачи, а не переводы. 50 задач не много. За месяц справятся.\n\nИдея простая, чистая, и попадает в самый центр того, что нам нужно. Активность на платформе. Новый контент. Качественный формат. Публичное признание для тех, кто реально работает. Я переделал предложение в формат, где у каждого активного автора есть шанс на приз, добавил множители за приоритетные направления и живую таблицу. Большое спасибо `emixter` за идею.\n\n## Что делать прямо сейчас\n\nЕсли ты уже зарегистрирован на платформе, открой список нерешённых задач, выбери главу, которая тебе ближе всего, и начинай публиковать решения в LaTeX. Конкурс уже идёт.\n\nЕсли ты ещё не зарегистрирован, регистрация бесплатна и занимает минуту. После неё сразу видны все нерешённые задачи и активные обсуждения.\n\nЕсли ты преподаёшь физику или ведёшь кружок, покажи эту страницу студентам. Конкурс отличный повод приобщить их к серьёзной работе с одним из лучших задачников по физике. Лучшие из них могут получить мерч и признание сообщества.\n\n---\n\n*Начало конкурса 1 июня 2026 года. Окончание 30 июня 2026 года, 23:59 по UTC. Победители объявляются 1 июля, мерч высылается в течение двух недель. Вопросы пишите в ALL чат или напрямую `astrosander` в личные сообщения. Удачи всем.*',
    E'С 1 по 30 июня 2026 года на savchenkosolutions.com проходит первый ежемесячный конкурс авторов. Публикуй новые решения в LaTeX, набирай баллы с множителями и выигрывай эксклюзивный фирменный мерч. Призы в трёх категориях и живая таблица результатов.',
    'ru',
    ARRAY['community','contest','merch','konkurs'],
    true,
    NOW()
);

COMMIT;
